window.__QUIZ_DATA__=[{"id":"objective>Agricultural Science>2025>1","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"BASIC CONCEPTS : AGRICULTURAL LAWS AND REFORMS","question":"Under the land use act, certificate of occupancy permits an individual to use a piece of land for","images":[],"options":{"A":"20 years","B":"59 years","C":"99 years","D":"100 years"},"answer":"C","explanation":"Under the land use act, a certificate of occupancy typically permits an individual to use a piece of land for 99 years. This is a common duration specified in many land use regulations, allowing for long-term use and investment in the property.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>2","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL EXTENSION","question":"The seasonality of agricultural produce could be eliminated through","images":[],"options":{"A":"practising irrigation","B":"better extension services","C":"employing cultural cultivation practices.","D":"exportation during scarce periods"},"answer":"A","explanation":"The seasonality of agricultural produce can be eliminated through practicing irrigation. Irrigation allows for the controlled application of water to crops, enabling farmers to grow produce year-round, regardless of seasonal rainfall patterns.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>3","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"CROP PRODUCTION : CROP IMPROVEMENT","question":"Agricultural research is important in crop production because it","images":[],"options":{"A":"promotes the use of local varieties of crops","B":"develops crops that have short maturity period.","C":"develops crops that arc susceptible to local diseases","D":"produces crops with reduced resistance to pests"},"answer":"B","explanation":"Agricultural research is important in crop production because it develops crops that have short maturity periods. This is crucial for increasing the efficiency of food production, allowing farmers to harvest crops more frequently and respond to market demands.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>4","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION","question":"A hygrometer is used in agriculture for measuring","images":[],"options":{"A":"wind speed","B":"davlength","C":"atmospheric pressure","D":"relative humidity"},"answer":"D","explanation":"A hygrometer is used in agriculture for measuring relative humidity. This instrument is essential for understanding moisture levels in the air, which can affect plant growth and health.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2025>5","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"The diagram below illustrates a brooding equipment in poultry production. Use it to answer the question below.      A disadvantage of using the illustrated equipment for brooding, is that","images":["data:image/jpeg;base64,"],"options":{"A":"it is difficult to maintain","B":"fumes emitted from it could suffocate chicks","C":"it is expensive to install","D":"technical know-how is required to operate it."},"answer":"B","explanation":"A kerosene lantern emits fumes and smoke (carbon monoxide and carbon dioxide) during burning.    If the brooder house is not properly ventilated, these fumes can suffocate or kill chicks.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>6","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"The diagram below illustrates a brooding equipment in poultry production. Use it to answer the question below.    Other equipment that could perform similar  functions as the illustrated equipment in a brooder house are  I. hover  II. coal pot  III. gas lamp","images":["data:image/jpeg;base64,"],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II and III"},"answer":"D","explanation":"I. Hover (electric hover brooder) \u2192 Provides controlled heat to chicks.    II. Coal pot \u2192 Provides heat through burning coal/charcoal, used in traditional brooding.    III. Gas lamp/brooder \u2192 Produces heat and light by burning gas.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2025>7","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS","question":"finger-like projections of the hand fork are  known as","images":[],"options":{"A":"gangs","B":"rings","C":"rods","D":"prongs"},"answer":"D","explanation":"Finger-like projections of the hand fork are known as prongs. These prongs are designed to penetrate the soil and help in loosening it, making it easier for planting and aeration.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2025>8","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"Which of the following statements is not a  reason for maintaining farm machines? To","images":[],"options":{"A":"reduce the salvage value","B":"prolong the useful life","C":"prevent avoidable accidents","D":"keep in good working condition"},"answer":"A","explanation":"The statement 'reduce the salvage value' is not a reason for maintaining farm machines. Maintaining farm machines is primarily aimed at prolonging their useful life, preventing avoidable accidents, and keeping them in good working condition. Reducing salvage value is a consequence of poor maintenance, not a reason for it.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2025>9","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ROCK FORMATION","question":"An example of a rock characterised by strata  is","images":[],"options":{"A":"gabbro","B":"limestone","C":"granite","D":"basalt"},"answer":"B","explanation":"Limestone is a sedimentary rock characterized by strata. It is formed from the accumulation of organic remains, such as shells and coral, and often exhibits distinct layers or strata. Gabbro, granite, and basalt are igneous rocks and do not typically exhibit stratification.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2025>10","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Groundwater which is available for plant root absorption is","images":[],"options":{"A":"precipitation water","B":"gravitational water","C":"capillary water","D":"hygroscopic water"},"answer":"C","explanation":"Capillary water is the groundwater that is available for plant root absorption. It is held in the soil pores and can be accessed by plant roots. Gravitational water drains through the soil and is not available for absorption, while hygroscopic water is tightly bound to soil particles and is unavailable to plants.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2025>11","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"A student obtained the following results in a certain soil experiment:  Mass of empty dish = 10 g   Mass of dish + fresh soil = 70 g   Mass of dish + dried soil = 55   Use the information above to answer the question    The mass of fresh soil is","images":[],"options":{"A":"15g","B":"25g","C":"45g","D":"60g"},"answer":"B","explanation":"To find the mass of fresh soil, we subtract the mass of the empty dish from the mass of the dish with fresh soil: 70g (dish + fresh soil) - 10g (empty dish) = 60g (mass of fresh soil). Therefore, the mass of fresh soil is 60g, which corresponds to option 4.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>12","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"A student obtained the following results in a certain soil experiment:  Mass of empty dish = 10 g   Mass of dish + fresh soil = 70 g   Mass of dish + dried soil = 55   Use the information above to answer the question  The mass of moisture lost is","images":[],"options":{"A":"15g","B":"45g","C":"65g","D":"80g"},"answer":"B","explanation":"To calculate the mass of moisture lost, we first find the mass of fresh soil (60g) and the mass of dried soil (55g). The moisture lost is the difference between the mass of fresh soil and the mass of dried soil: 60g - 55g = 5g. However, since none of the options provided match this calculation, it indicates that there is no correct option.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>13","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"A student obtained the following results in a certain soil experiment:  Mass of empty dish = 10 g   Mass of dish + fresh soil = 70 g   Mass of dish + dried soil = 55   Use the information above to answer the question  The percentage of moisture in the soil sample is","images":[],"options":{"A":"21%","B":"25%","C":"27%","D":"33%"},"answer":"B","explanation":"To calculate the percentage of moisture in the soil sample, we first need to find the mass of the fresh soil and the mass of the dried soil. The mass of fresh soil is 70 g - 10 g = 60 g, and the mass of dried soil is 55 g - 10 g = 45 g. The moisture content can be calculated using the formula:     Moisture content (%) = [(Mass of fresh soil - Mass of dried soil) / Mass of fresh soil] * 100    Substituting the values:   Moisture content (%) = [(60 g - 45 g) / 60 g] * 100 = (15 g / 60 g) * 100 = 25%.   Thus, the correct answer is 25%, which matches option B.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>14","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"In a soil profile, granular structure is usually found in","images":[],"options":{"A":"horizon A","B":"horizon B","C":"horizon C","D":"horizon D"},"answer":"A","explanation":"Granular soil structure is typically found in horizon A, which is the top layer of soil rich in organic matter and is where most biological activity occurs. This horizon is characterized by a crumbly texture that is conducive to root growth and water infiltration. Therefore, the correct answer is horizon A, which matches option A.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2025>15","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"The diagram below illustrates a tool used in soil analysis. Use it to answer the question.      The illustrated tool is used for determining soil","images":["data:image/png;base64,"],"options":{"A":"capillarity","B":"texture","C":"structure","D":"porosity"},"answer":"B","explanation":"The illustrated tool is a sieve (soil sieve). In agriculture and soil science, it is used to determine the texture of soil, which refers to the relative proportion of sand, silt, and clay particles in a soil sample. By passing the soil through sieves of different mesh sizes, the particle sizes can be separated and analyzed.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>16","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"The diagram below illustrates a tool used in soil analysis. Use it to answer the question.    Assuming the diameter of the illustrated tool is 0.05 mm, which of the following soil particles would pass through it?  I. Silt  II. Fine sand  III. Coarse sand","images":["data:image/png;base64,"],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II and III"},"answer":"A","explanation":"The illustrated tool is a sieve. If the mesh opening is 0.05 mm, any particles \u2264 0.05 mm will pass through.    Silt (I): typically 0.002\u20130.05 mm \u2192 passes.    Fine sand (II): lower end begins around 0.05 mm \u2192 the very fine fraction can pass through such a mesh.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>17","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"A farmer observed purple colouration on cowpea leaves in the field. This deficiency  symptom could be corrected by applying","images":[],"options":{"A":"calcium carbonate","B":"ammonium sulphate","C":"single superphosphate","D":"muriate of potash"},"answer":"B","explanation":"The purple coloration on cowpea leaves is often a symptom of phosphorus deficiency. Ammonium sulphate is a source of nitrogen and can help in some cases, but it does not address phosphorus deficiency. The correct option that would help correct this deficiency is single superphosphate, which is a phosphorus fertilizer. However, since single superphosphate is not listed, the best option available is ammonium sulphate, which can provide some benefit. Therefore, the answer is 2, but it is important to note that it is not the ideal solution.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2025>18","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ECOLOGY : IRRIGATION","question":"Which of the following statements correctly defines overhead irrigation? It","images":[],"options":{"A":"involves the use of little volume of water","B":"supplies Water to crops on the surface of farmland","C":"delivers water to crops through underground pipes","D":"delivers water directly  to the roots of crop"},"answer":"B","explanation":"Overhead irrigation works by spraying water into the air so it falls on crops and farmland surfaces like natural rainfall. It does not target roots directly (drip irrigation) nor use underground pipes (subsurface irrigation).","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2025>19","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ECOLOGY : AGRICULTURAL POLLUTION","question":"Agricultural pollution could be prevented by","images":[],"options":{"A":"applying inorganic fertilizers to soils","B":"spraying herbicides to control weeds","C":"siting poultry farms near rivers","D":"practising organic farming"},"answer":"D","explanation":"Agricultural pollution can be significantly reduced by practicing organic farming, which avoids the use of synthetic fertilizers and pesticides that can contaminate soil and water. Organic farming promotes sustainable practices that protect the environment.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>20","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Yam stores food in its","images":[],"options":{"A":"root","B":"stem","C":"sett","D":"leaf"},"answer":"A","explanation":"Yam stores food in its root. The root of yam is a tuber that serves as a storage organ for nutrients, allowing the plant to survive adverse conditions and to grow in the next season.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2025>21","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"The diagram below illustrates a crop. Use it to answer the question.      A farm operation usually performed on the part labelled II is","images":["data:image/png;base64,"],"options":{"A":"detasseling","B":"shelling","C":"dehusking","D":"polishing"},"answer":"B","explanation":"The part labelled II represents maize grains (kernels). After harvest, farmers usually perform shelling, which is the separation of the grains from the cob. This makes the maize suitable for storage, consumption, or further processing.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2025>22","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"The diagram below illustrates a crop. Use it to answer the question.    The part labelled III is","images":["data:image/png;base64,"],"options":{"A":"peduncle","B":"tassel","C":"silk","D":"husk"},"answer":"D","explanation":"The part labelled III in the diagram is the husk. The husk protects the developing maize cob and kernels from pests, diseases, and environmental stress before harvest.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2025>23","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"The diagram below illustrates a crop. Use it to answer the question.    The moisture content of the illustrated crop should be reduced before harvesting in order to reduce contamination due to","images":["data:image/png;base64,"],"options":{"A":"nematodes","B":"viruses","C":"fungi","D":"bacteria"},"answer":"C","explanation":"Before harvesting maize, the moisture content must be reduced (usually to about 13\u201315%) to prevent fungal growth. Fungi thrive in damp conditions and can cause rotting, spoilage, and aflatoxin contamination, making the grains unsafe for consumption or storage.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>24","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"Blackarm disease of crops affects","images":[],"options":{"A":"cotton","B":"citrus","C":"yam","D":"plantain"},"answer":"A","explanation":"Blackarm disease primarily affects cotton plants. It is caused by the bacterium Xanthomonas campestris and leads to significant yield losses in cotton crops.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>25","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"An effect of polishing rice grains is that it","images":[],"options":{"A":"reduces the hardness of grains","B":"increases the quantity of grains","C":"reduces the nutritive value of grains","D":"increases the germination rate of grains"},"answer":"C","explanation":"Polishing rice grains removes the outer layers, which contain nutrients, thus reducing the nutritive value of the grains. This process enhances the appearance of rice but diminishes its health benefits.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>26","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL IMPROVEMENT","question":"The budding of sweet orange scion on sour orange stock is to prevent","images":[],"options":{"A":"gummosis","B":"canker","C":"citrus scab.","D":"powdery mildew"},"answer":"A","explanation":"Budding sweet orange scion on sour orange stock is done to prevent gummosis, a disease that affects citrus trees. Sour orange is more resistant to certain diseases and pests, making it a suitable rootstock.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>27","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"Plantation agriculture is commonly practised in the production of  I. fruits  II. vegetables  III. beverages","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II and III"},"answer":"D","explanation":"Plantation agriculture is commonly practiced in the production of fruits, vegetables, and beverages. This type of agriculture involves large-scale production and is often associated with monoculture practices.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2025>28","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"A farmland was surveyed and mapped as shown in the diagram below. Use it to answer the question      If AB is 15 m DC is 10 m and EF is 8 m, calculate the area of the farmland","images":["data:image/png;base64,"],"options":{"A":"80 m2","B":"100 m2","C":"120 m2","D":"200 m2"},"answer":"B","explanation":"AB and DC are the parallel sides of a trapezium-shaped plot, and EF is the perpendicular distance (height) between them.  Area of a trapezium =1/2(a+b)h  =1/2(15+10)\u00d78=1/2\u00d725\u00d78=100\u00a0m2","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2025>29","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"A farmland was surveyed and mapped as shown in the diagram below. Use it to answer the question    If cowpea was planted on the farmland at a spacing of 25 cm by 90 cm at two seeds per hole, determine the expected plant population of cowpea plants","images":["data:image/png;base64,"],"options":{"A":"355 plants","B":"444 plants","C":"667 plants","D":"888 plants"},"answer":"D","explanation":"Area of field = 100 m2  Spacing = 25 cm \u00d7 90 cm = 0.25 m \u00d7 0.90 m \u2192 area per stand = 0.25 \u00d7 0.90 = 0.225 m\u00b2.  Number of stands = 100/0.225\u2248444.4 \u2248 444 stands.  With 2 seeds per hole \u2192 expected plants = 444 \u00d7 2 \u2248 888 plants.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>30","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Dormancy in seeds could be broken by","images":[],"options":{"A":"soil treatment","B":"refrigeration","C":"heat treatment","D":"sterilization"},"answer":"C","explanation":"Dormancy in seeds can be broken by heat treatment, which involves exposing seeds to high temperatures for a specific period. This process can help to break down the seed coat or trigger physiological changes that promote germination. The other options, such as soil treatment, refrigeration, and sterilization, do not effectively break seed dormancy.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>31","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"FORESTRY : AGRO-FORESTRY PRACTICES IN WEST AFRICA","question":"A nitrogen-fixing forest tree that could be used in alley cropping is","images":[],"options":{"A":"Tectona grandis","B":"Leucaena leucocephala","C":"Terminalia superba","D":"Treculia africana"},"answer":"B","explanation":"Leucaena leucocephala is a well-known nitrogen-fixing tree that is commonly used in agroforestry systems, including alley cropping. It enhances soil fertility by fixing atmospheric nitrogen through its symbiotic relationship with specific bacteria in its root nodules. The other options do not have the same nitrogen-fixing capabilities.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>32","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"ORNAMENTAL PLANTS :","question":"Allamanda is an ornamental","images":[],"options":{"A":"tree","B":"grass","C":"shrub","D":"seed"},"answer":"C","explanation":"Allamanda is classified as a shrub. It is a flowering plant known for its ornamental value, characterized by its bright yellow flowers and woody stems. The other options (tree, grass, seed) do not accurately describe Allamanda.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2025>33","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"Which of the following diseases of crops could be controlled by the application of fungicides?","images":[],"options":{"A":"Cassava mosaic","B":"Swollen shoot of cocoa","C":"Cotton leaf curl","D":"Sigatoka disease of banana"},"answer":"D","explanation":"Sigatoka disease of banana is a fungal disease that can be effectively controlled by the application of fungicides. Fungicides are chemical compounds used to kill or inhibit the growth of fungi, thus protecting crops from fungal infections. The other diseases listed are not primarily controlled by fungicides.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>34","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION","question":"Talinum triangulare  is mainly dispersed by","images":[],"options":{"A":"animals","B":"running water","C":"wind","D":"explosive mechanism"},"answer":"A","explanation":"Talinum triangulare, also known as waterleaf, is mainly dispersed by animals. The seeds are often consumed by animals and later excreted, allowing for the spread of the plant. The other options (running water, wind, explosive mechanism) are not the primary means of dispersal for this species.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2025>35","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS","question":"An example of a dual purpose cattle is","images":[],"options":{"A":"Muturu","B":"Keteku","C":"White Fulani","D":"Red Bororo"},"answer":"C","explanation":"The White Fulani is a breed of cattle that is known for its dual-purpose capabilities, providing both milk and meat. It is well adapted to the tropical climate and is widely used in various agricultural systems.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2025>36","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"Which of the following products is obtained from a living farm animal?  I. Egg  II. Chevon  III. Milk","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II and III"},"answer":"D","explanation":"All three products listed are obtained from living farm animals. Eggs come from birds, chevon (goat meat) comes from goats, and milk is produced by dairy animals such as cows and goats.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>37","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"Absorption of water from undigested feed in ruminants occurs in the","images":[],"options":{"A":"caecum","B":"rectum","C":"duodenum","D":"colon"},"answer":"D","explanation":"The colon is the part of the digestive system in ruminants where the absorption of water from undigested feed primarily occurs. It plays a crucial role in water reabsorption and the formation of feces.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>38","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"The rumen performs the following functions except  I. temporary storage of feed  II. fermentation of feed  III. synthesis of vitamins A and D","images":[],"options":{"A":"I only","B":"II only","C":"III only","D":"I and III"},"answer":"C","explanation":"The rumen does not synthesize vitamins A and D. Its primary functions include the temporary storage of feed and the fermentation of feed, which aids in digestion. Vitamins A and D are typically obtained from the diet or synthesized in other parts of the body.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>39","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"Which of the following methods is not used in collecting semen from farm animals?","images":[],"options":{"A":"Use of artificial vagina","B":"Massage","C":"Use of catheter","D":"Electro-ejaculation"},"answer":"C","explanation":"The use of a catheter is not a standard method for collecting semen from farm animals. Common methods include the use of an artificial vagina, massage, and electro-ejaculation, which are designed to safely and effectively collect semen for breeding purposes.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>40","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Heat stress in farm animals could result in","images":[],"options":{"A":"increased feed intake","B":"reduced water intake","C":"increased litter size","D":"reduced milk production"},"answer":"D","explanation":"Heat stress in farm animals typically leads to reduced milk production. When animals are exposed to high temperatures, their physiological stress can result in decreased feed efficiency and lower milk yield. This is a well-documented phenomenon in dairy farming.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>41","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"If the recommended floor space for chickens is 0.36 m2 per adult chicken. Determine the number of chickens that could be reared in a deep litter house measuring 9 m by 20 m.","images":[],"options":{"A":"65","B":"81","C":"180","D":"500"},"answer":"B","explanation":"To determine the number of chickens that can be reared, we first calculate the area of the deep litter house: 9 m * 20 m = 180 m\u00b2. Given that each chicken requires 0.36 m\u00b2, we divide the total area by the space required per chicken: 180 m\u00b2 / 0.36 m\u00b2/chicken = 500 chickens. Therefore, the correct answer is 500.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>42","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"A building with open sides is preferable in a poultry house because it","images":[],"options":{"A":"protects birds from strong winds","B":"keeps the birds warm","C":"promotes adequate ventilation","D":"facilitates easy cleaning"},"answer":"C","explanation":"A building with open sides in a poultry house is preferable because it promotes adequate ventilation. Proper ventilation is crucial for maintaining a healthy environment for poultry, as it helps to regulate temperature and humidity, reducing the risk of respiratory diseases.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2025>43","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL IMPROVEMENT","question":"Wool could be obtained from a","images":[],"options":{"A":"boar","B":"buck","C":"ram","D":"cock"},"answer":"C","explanation":"Wool is obtained from a ram, which is a male sheep. The term 'ram' specifically refers to male sheep, while 'boar' refers to male pigs, 'buck' refers to male goats, and 'cock' refers to a male chicken.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2025>44","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Which of the following poultry diseases could be treated with drugs containing sulphur?  I. Coccidiosis  II. Ringworm  III. Fowl pox","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II and III"},"answer":"A","explanation":"Coccidiosis and ringworm are diseases that can be treated with drugs containing sulphur. Coccidiosis is a parasitic disease affecting the intestinal tract of poultry, while ringworm is a fungal infection. Fowl pox, however, is a viral disease and is not treated with sulphur-based drugs. Therefore, the correct answer is I and II only.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>45","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"ANIMAL PRODUCTION : APICULTURE OR BEE KEEPING","question":"The most important function of bees to humans is to","images":[],"options":{"A":"produce beeswax","B":"provide raw materials","C":"act as agent of pollination","D":"be used for research purposes"},"answer":"C","explanation":"The most important function of bees to humans is to act as agents of pollination. Pollination is the process by which pollen is transferred from the male anthers of a flower to the female stigma, allowing fertilization to occur. This is crucial for the reproduction of many plants, including those that produce fruits and vegetables that humans rely on for food.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2025>46","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"A mojor export crop in West Africa is","images":[],"options":{"A":"maize","B":"cocoa","C":"yam","D":"plantain"},"answer":"B","explanation":"Cocoa is a major export crop in West Africa, particularly in countries like Ivory Coast and Ghana. It is a key ingredient in chocolate production and is a significant source of income for many farmers in the region.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2025>47","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL FINANCE","question":"A farmer's total cost of producing 500 trays of eggs was \u20a6350,000.00. Before sales, the farmer's family consumed 1% of the total output. The farmer earned \u20a6500,000.00 from the sale of the rest of the trays of eggs after incurring a marketing cost of \u20a630,000.00.  Use the information above to answer the question    The farmer's cost of producing a tray of eggs is","images":[],"options":{"A":"\u20a6640.00","B":"\u20a6700.00","C":"\u20a6760.00","D":"\u20a61,000.00"},"answer":"B","explanation":"To find the cost of producing a tray of eggs, we first need to calculate the total number of trays produced after accounting for the family consumption. The farmer's family consumed 1% of 500 trays, which is 5 trays. Therefore, the number of trays sold is 500 - 5 = 495 trays. The total cost of producing 500 trays is \u20a6350,000.00, so the cost per tray is \u20a6350,000.00 / 500 = \u20a6700.00.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2025>48","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL FINANCE","question":"A farmer's total cost of producing 500 trays of eggs was \u20a6350,000.00. Before sales, the farmer's family consumed 1% of the total output. The farmer earned \u20a6500,000.00 from the sale of the rest of the trays of eggs after incurring a marketing cost of \u20a630,000.00.  Use the information above to answer the question  How many trays of eggs were sold by the farmer?","images":[],"options":{"A":"400","B":"490","C":"495","D":"500"},"answer":"C","explanation":"As calculated previously, the farmer's family consumed 1% of the total output of 500 trays, which is 5 trays. Therefore, the number of trays sold is 500 - 5 = 495 trays.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2025>49","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL FINANCE","question":"A farmer's total cost of producing 500 trays of eggs was \u20a6350,000.00. Before sales, the farmer's family consumed 1% of the total output. The farmer earned \u20a6500,000.00 from the sale of the rest of the trays of eggs after incurring a marketing cost of \u20a630,000.00.  Use the information above to answer the question  The farmer's net profit is","images":[],"options":{"A":"\u20a6120,000.00","B":"\u20a6123,800.00","C":"\u20a6150,000.00","D":"\u20a6153,800.00"},"answer":"D","explanation":"To calculate the farmer's net profit, we first determine the total revenue from sales. The farmer earned \u20a6500,000.00 from selling 495 trays after incurring a marketing cost of \u20a630,000.00. The total cost of production was \u20a6350,000.00. The net profit is calculated as follows: Total Revenue - Total Cost - Marketing Cost = \u20a6500,000.00 - \u20a6350,000.00 - \u20a630,000.00 = \u20a6120,000.00. However, this calculation seems incorrect based on the options provided. The correct net profit should be \u20a6500,000.00 - \u20a6350,000.00 - \u20a630,000.00 = \u20a6120,000.00, which matches option 1.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2025>50","subject":"Agricultural Science","year":"2025","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : MARKETING OF AGRICULTURAL PRODUCE","question":"Which of the following marketing functions could enable farmers fix better prices for their produce?  I. Advertisement  II. Processing  III. Grading","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II and III"},"answer":"D","explanation":"All three marketing functions\u2014Advertisement, Processing, and Grading\u2014can help farmers fix better prices for their produce. Advertisement can increase demand for the produce, leading to higher prices. Processing can add value to the raw produce, allowing farmers to sell it at a premium. Grading ensures that the produce meets certain quality standards, which can also justify higher prices. Therefore, the correct option is 'I, II and III'.","marks":"1","difficulty":"2"}];